import{_ as e,o as s,c as n,a2 as i}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Arquitectura full stack","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/01-introduccion.md","filePath":"full-stack/arquitectura/01-introduccion.md","lastUpdated":1782521464000}'),t={name:"full-stack/arquitectura/01-introduccion.md"};function o(r,a,l,c,d,p){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="arquitectura-full-stack" tabindex="-1">Arquitectura full stack <a class="header-anchor" href="#arquitectura-full-stack" aria-label="Permalink to &quot;Arquitectura full stack&quot;">​</a></h1><p>La arquitectura full stack define cómo se organizan frontend, backend, base de datos, servicios externos, despliegue, seguridad y observabilidad dentro de una aplicación.</p><h2 id="conceptos-clave" tabindex="-1">Conceptos clave <a class="header-anchor" href="#conceptos-clave" aria-label="Permalink to &quot;Conceptos clave&quot;">​</a></h2><ul><li><strong>Frontend:</strong> interfaz que usa la persona usuaria.</li><li><strong>Backend:</strong> lógica de negocio, APIs, autenticación y acceso a datos.</li><li><strong>Base de datos:</strong> persistencia de información.</li><li><strong>API:</strong> contrato de comunicación entre cliente y servidor.</li><li><strong>Autenticación:</strong> verificación de identidad.</li><li><strong>Autorización:</strong> control de permisos.</li><li><strong>Despliegue:</strong> publicación de la aplicación en un entorno.</li><li><strong>Observabilidad:</strong> logs, métricas y trazas.</li></ul><h2 id="arquitectura-basica" tabindex="-1">Arquitectura básica <a class="header-anchor" href="#arquitectura-basica" aria-label="Permalink to &quot;Arquitectura básica&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Navegador</span></span>
<span class="line"><span>  -&gt; Frontend</span></span>
<span class="line"><span>  -&gt; API backend</span></span>
<span class="line"><span>  -&gt; Base de datos</span></span></code></pre></div><p>Esta arquitectura es suficiente para muchas aplicaciones CRUD, dashboards internos y proyectos de portfolio.</p><h2 id="capas-habituales" tabindex="-1">Capas habituales <a class="header-anchor" href="#capas-habituales" aria-label="Permalink to &quot;Capas habituales&quot;">​</a></h2><h3 id="presentacion" tabindex="-1">Presentación <a class="header-anchor" href="#presentacion" aria-label="Permalink to &quot;Presentación&quot;">​</a></h3><p>Componentes, rutas, formularios, estado de interfaz y validaciones visuales.</p><h3 id="aplicacion" tabindex="-1">Aplicación <a class="header-anchor" href="#aplicacion" aria-label="Permalink to &quot;Aplicación&quot;">​</a></h3><p>Casos de uso, servicios, controladores y coordinación de operaciones.</p><h3 id="dominio" tabindex="-1">Dominio <a class="header-anchor" href="#dominio" aria-label="Permalink to &quot;Dominio&quot;">​</a></h3><p>Reglas de negocio y entidades principales.</p><h3 id="infraestructura" tabindex="-1">Infraestructura <a class="header-anchor" href="#infraestructura" aria-label="Permalink to &quot;Infraestructura&quot;">​</a></h3><p>Base de datos, proveedores externos, sistema de archivos, colas, logs y clientes HTTP.</p><h2 id="ejemplos-practicos" tabindex="-1">Ejemplos prácticos <a class="header-anchor" href="#ejemplos-practicos" aria-label="Permalink to &quot;Ejemplos prácticos&quot;">​</a></h2><h3 id="flujo-de-login" tabindex="-1">Flujo de login <a class="header-anchor" href="#flujo-de-login" aria-label="Permalink to &quot;Flujo de login&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Formulario -&gt; API /login -&gt; validación -&gt; token/session -&gt; almacenamiento seguro -&gt; rutas protegidas</span></span></code></pre></div><h3 id="flujo-crud" tabindex="-1">Flujo CRUD <a class="header-anchor" href="#flujo-crud" aria-label="Permalink to &quot;Flujo CRUD&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Lista -&gt; formulario -&gt; validación frontend -&gt; API -&gt; validación backend -&gt; base de datos -&gt; respuesta</span></span></code></pre></div><h3 id="estructura-orientativa-de-backend" tabindex="-1">Estructura orientativa de backend <a class="header-anchor" href="#estructura-orientativa-de-backend" aria-label="Permalink to &quot;Estructura orientativa de backend&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── controllers/</span></span>
<span class="line"><span>├── services/</span></span>
<span class="line"><span>├── repositories/</span></span>
<span class="line"><span>├── models/</span></span>
<span class="line"><span>├── middlewares/</span></span>
<span class="line"><span>└── config/</span></span></code></pre></div><h2 id="buenas-practicas" tabindex="-1">Buenas prácticas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas prácticas&quot;">​</a></h2><ul><li>Mantén reglas críticas en backend, aunque también valides en frontend.</li><li>Usa DTOs o contratos claros entre frontend y backend.</li><li>Separa lógica de negocio de controladores.</li><li>Centraliza gestión de errores.</li><li>No expongas secretos en el cliente.</li><li>Documenta endpoints y códigos de respuesta.</li><li>Añade logs útiles para diagnosticar fallos.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Poner toda la lógica en componentes frontend.</li><li>Mezclar acceso a datos directamente en controladores.</li><li>No validar datos en backend.</li><li>Guardar tokens inseguros sin estrategia clara.</li><li>Diseñar APIs sin criterios de paginación, filtros o errores.</li></ul><h2 id="chuleta-rapida" tabindex="-1">Chuleta rápida <a class="header-anchor" href="#chuleta-rapida" aria-label="Permalink to &quot;Chuleta rápida&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Frontend: UI y experiencia</span></span>
<span class="line"><span>Backend: reglas y APIs</span></span>
<span class="line"><span>DB: persistencia</span></span>
<span class="line"><span>Auth: identidad y permisos</span></span>
<span class="line"><span>Logs: diagnóstico</span></span>
<span class="line"><span>Deploy: publicación</span></span></code></pre></div><h2 id="recursos-relacionados" tabindex="-1">Recursos relacionados <a class="header-anchor" href="#recursos-relacionados" aria-label="Permalink to &quot;Recursos relacionados&quot;">​</a></h2><ul><li><a href="./../frontend/angular/README">Angular</a></li><li><a href="./../frontend/react/README">React</a></li><li><a href="./../backend/php/tienda-online-con-php">PHP</a></li><li><a href="./../../bases-de-datos/sql/README">SQL</a></li></ul>`,31)])])}const g=e(t,[["render",o]]);export{h as __pageData,g as default};
